class A:
    def __init__(self, x):
        self.x = x

class B(A):
    def __init__(self, x, y):
        super().__init__(x)
        self.y = y

obj = B(10, 20)
print(obj.x, obj.y)

ShortQuestions.preferredAnswer:
Method overriding occurs when a subclass provides a different implementation of a method that is already defined in its parent class. The method has the same name and parameters.

Method overloading means having multiple methods with the same name but different parameters. Python doesn't support traditional overloading, but you can simulate it with default parameters or variable arguments.

Example of overriding:
class Animal:
    def make_sound(self):
        return 'Some sound'

class Dog(Animal):
    def make_sound(self):  # Overriding
        return 'Bark'

Example simulating overloading in Python:
def add(a, b, c=None):
    if c is None:
        return a + b
    else:
        return a + b + c

class InvalidEmailError(Exception):
    def __init__(self, email, message='Invalid email format'):
        self.email = email
        self.message = message
        super().__init__(f'{message}: {email}')

def validate_email(email):
    if not isinstance(email, str):
        raise InvalidEmailError(email, 'Email must be a string')
    if '@' not in email:
        raise InvalidEmailError(email, 'Email must contain @ symbol')
    if '.' not in email.split('@')[-1]:
        raise InvalidEmailError(email, 'Email must have domain with dot')
    return True

# Usage
try:
    validate_email('invalid-email')
except InvalidEmailError as e:
    print(f'Error: {e}')
